BEGIN;
-- ── 1. Health Informatics Specialists (15-1211.01) ──────────
INSERT INTO agent_logic (primary_directive, step_by_step_json, toolbox_requirements) VALUES (
'Apply nursing and informatics knowledge to design, implement, and evaluate computerized healthcare systems that improve patient care and data quality.',
'[
  {"step":1,"type":"tool_use","name":"assess_clinical_requirements","description":"Analyze clinical workflows and data needs with nursing and technical stakeholders","input":{"action":"requirements_gathering","methods":["stakeholder_interviews","workflow_mapping","EHR_audit"]},"definition_of_done":"Clinical requirements document approved by nursing leadership and IT"},
  {"step":2,"type":"tool_use","name":"design_informatics_solution","description":"Translate nursing practice information into system specifications for engineers","input":{"action":"create_spec","tools":["Epic_Systems","MEDITECH","Lucidchart"],"artifacts":["data_model","workflow_diagram","interface_spec"]},"definition_of_done":"System spec reviewed by clinical informatics team and approved"},
  {"step":3,"type":"tool_use","name":"implement_and_configure","description":"Implement EHR modifications, decision-support tools, and data pipelines","input":{"action":"configure_system","platforms":["Epic","MEDITECH","eClinicalWorks"],"languages":["SQL","Python","R"]},"definition_of_done":"System configured, unit tested, and validated against clinical scenarios"},
  {"step":4,"type":"tool_use","name":"ensure_data_privacy","description":"Implement and audit policies for patient data privacy, confidentiality, and security","input":{"action":"privacy_audit","frameworks":["HIPAA","HL7_FHIR"],"tools":["SharePoint","IBM_SPSS"]},"definition_of_done":"Privacy controls verified, no PHI exposure in test or prod environments"},
  {"step":5,"type":"tool_use","name":"analyze_clinical_data","description":"Analyze patient and system data to identify improvement opportunities","input":{"action":"run_analysis","tools":["Tableau","Power_BI","SAS","Apache_Hadoop"],"outputs":["clinical_dashboard","quality_metrics_report"]},"definition_of_done":"Analysis report delivered to stakeholders, KPIs trending in expected direction"},
  {"step":6,"type":"tool_use","name":"train_clinical_staff","description":"Develop and deliver training programs for health IT systems","input":{"action":"deliver_training","format":["live_session","e-learning","quick_reference_card"],"audience":["nurses","physicians","admin_staff"]},"definition_of_done":"Training completion rate >= 95%, post-training competency score >= 80%"}
]'::jsonb,
ARRAY['Epic Systems','MEDITECH','eClinicalWorks','SQL','Python','R','Tableau','Power BI','SAS','IBM SPSS Statistics','Apache Hadoop','Microsoft SharePoint','Microsoft Excel','HL7 FHIR']
);

-- ── 2. Computer and Information Research Scientists (15-1221.00) ──
INSERT INTO agent_logic (primary_directive, step_by_step_json, toolbox_requirements) VALUES (
'Conduct original research in fundamental computer and information science to solve complex computational problems and develop innovative technologies.',
'[
  {"step":1,"type":"tool_use","name":"identify_research_problem","description":"Analyze existing computational limitations and define research hypotheses","input":{"action":"literature_review","tools":["Google_Scholar","IEEE_Xplore","ACM_Digital_Library"]},"definition_of_done":"Research proposal accepted with clearly scoped hypothesis and success metrics"},
  {"step":2,"type":"tool_use","name":"design_experiment","description":"Design logical analyses and computational experiments to test hypotheses","input":{"action":"design_study","tools":["MATLAB","TensorFlow","IBM_SPSS"],"artifacts":["experiment_protocol","dataset_spec","evaluation_criteria"]},"definition_of_done":"Experiment design peer-reviewed and approved by research team"},
  {"step":3,"type":"tool_use","name":"implement_prototype","description":"Build prototype systems or algorithms to validate theoretical work","input":{"action":"develop_prototype","languages":["Python","Java","Scala","Go"],"infrastructure":["Docker","Kubernetes","AWS_SageMaker"]},"definition_of_done":"Prototype runs reproducibly, baseline results documented"},
  {"step":4,"type":"tool_use","name":"run_and_analyze_experiments","description":"Execute experiments, collect data, and apply statistical analysis","input":{"action":"run_experiments","tools":["Apache_Spark","Power_BI","Elasticsearch","Redis"],"methods":["ablation_study","benchmark_comparison"]},"definition_of_done":"Results statistically significant, methodology is reproducible"},
  {"step":5,"type":"tool_use","name":"publish_findings","description":"Prepare and submit research findings to peer-reviewed publications and conferences","input":{"action":"write_paper","tools":["LaTeX","Overleaf","GitHub"],"venues":["IEEE","ACM","NeurIPS","ICML"]},"definition_of_done":"Paper accepted at target venue or posted to arXiv with peer review initiated"},
  {"step":6,"type":"tool_use","name":"transfer_to_applied_teams","description":"Collaborate with engineering teams to transfer research outcomes to production systems","input":{"action":"knowledge_transfer","artifacts":["technical_report","API_spec","reference_implementation"]},"definition_of_done":"Applied team can reproduce results independently; handoff doc complete"}
]'::jsonb,
ARRAY['Python','Java','Scala','Go','TensorFlow','MATLAB','IBM SPSS Statistics','Apache Spark','Power BI','Tableau','AWS SageMaker','Docker','Kubernetes','Elasticsearch','Redis','Amazon DynamoDB','GitHub','Eclipse IDE']
);

-- ── 3. Computer Network Support Specialists (15-1231.00) ────
INSERT INTO agent_logic (primary_directive, step_by_step_json, toolbox_requirements) VALUES (
'Analyze, test, troubleshoot, and evaluate existing network systems including LAN, WAN, and cloud networks to maintain reliable and secure connectivity.',
'[
  {"step":1,"type":"tool_use","name":"assess_network_health","description":"Run diagnostic tests to baseline network performance and identify anomalies","input":{"action":"run_diagnostics","tools":["Wireshark","Nagios","OmniPeek"],"scope":["LAN","WAN","cloud","VPN"]},"definition_of_done":"Network health report generated, all anomalies categorized by severity"},
  {"step":2,"type":"tool_use","name":"identify_root_cause","description":"Trace networking problems to root cause using diagnostic software and equipment","input":{"action":"root_cause_analysis","tools":["CiscoWorks","HP_Network_Node_Manager","PowerShell"],"methods":["packet_capture","log_analysis","topology_review"]},"definition_of_done":"Root cause documented with supporting evidence, ticket updated"},
  {"step":3,"type":"tool_use","name":"configure_fix","description":"Apply configuration changes to routers, switches, and security settings","input":{"action":"apply_remediation","platforms":["Windows_Server","Linux","Cisco_IOS"],"tools":["Python","PowerShell"]},"definition_of_done":"Configuration change applied, change log updated, rollback plan documented"},
  {"step":4,"type":"tool_use","name":"verify_resolution","description":"Retest network after fix to confirm problem is resolved and performance restored","input":{"action":"post-fix_validation","tools":["Wireshark","Nagios","Splunk_Enterprise"],"thresholds":{"latency_ms":50,"packet_loss_pct":0}},"definition_of_done":"Network metrics within SLA, no recurrence within 24h monitoring window"},
  {"step":5,"type":"tool_use","name":"document_and_report","description":"Document network support activities, breaches, and resolution steps","input":{"action":"document","tools":["ServiceNow","Confluence","JIRA"],"artifacts":["incident_report","network_topology_update"]},"definition_of_done":"Incident closed in ticketing system, topology diagrams updated"},
  {"step":6,"type":"tool_use","name":"backup_and_harden","description":"Back up network configurations and apply security hardening measures","input":{"action":"backup_and_secure","tools":["Splunk","IBM_WebSphere","firewall_mgmt"],"schedule":"weekly_config_backup"},"definition_of_done":"Backup verified restorable, security scan shows no new vulnerabilities"}
]'::jsonb,
ARRAY['Wireshark','Nagios','OmniPeek','CiscoWorks','HP Network Node Manager','Splunk Enterprise','PowerShell','Python','Windows Server','Linux','UNIX','MySQL','SQL Server','Teradata']
);

-- ── 4. Computer User Support Specialists (15-1232.00) ───────
INSERT INTO agent_logic (primary_directive, step_by_step_json, toolbox_requirements) VALUES (
'Provide technical assistance to end users by diagnosing and resolving computer hardware, software, and network problems via phone, remote access, or in-person support.',
'[
  {"step":1,"type":"tool_use","name":"intake_and_triage","description":"Receive, log, and prioritize support requests from users","input":{"action":"create_ticket","tools":["ServiceNow","JIRA","Zendesk"],"fields":["issue_description","priority","user_info","affected_system"]},"definition_of_done":"Ticket created with priority assigned, user acknowledged within SLA"},
  {"step":2,"type":"tool_use","name":"diagnose_issue","description":"Investigate hardware, software, or OS problems using diagnostics and user interviews","input":{"action":"diagnose","tools":["Remote_Desktop","Windows_Event_Viewer","Device_Manager","Wireshark"],"methods":["log_review","remote_session","on-site_inspection"]},"definition_of_done":"Root cause identified or issue escalated with full diagnostic notes"},
  {"step":3,"type":"tool_use","name":"resolve_or_escalate","description":"Apply fix or escalate to Tier 2/3 with complete context","input":{"action":"resolve","tools":["Microsoft_Active_Directory","Group_Policy","Docker","ServiceNow"],"escalation_path":["Tier2_Network","Tier2_Security","Tier3_Engineering"]},"definition_of_done":"Issue resolved and verified with user, or escalation ticket created with full rundown"},
  {"step":4,"type":"tool_use","name":"install_and_configure","description":"Set up equipment, install OS, drivers, and required software for users","input":{"action":"provision_endpoint","tools":["SCCM","Intune","GitHub","Spring_Boot"],"standards":["SOE_image","security_baseline","approved_software_list"]},"definition_of_done":"Device configured per standard build, user can log in and access required systems"},
  {"step":5,"type":"tool_use","name":"monitor_system_performance","description":"Oversee daily performance of systems and proactively flag degradation","input":{"action":"monitor","tools":["Nagios","Splunk","Microsoft_Teams","Salesforce"],"frequency":"daily_health_check"},"definition_of_done":"Daily health check logged, no open P1 incidents unacknowledged"},
  {"step":6,"type":"tool_use","name":"gather_requirements_for_improvement","description":"Confer with users and management to identify needs for system modifications","input":{"action":"requirements_capture","tools":["Confluence","Microsoft_Excel","Zoom"],"output":"improvement_request_doc"},"definition_of_done":"Requirements documented and submitted to Tier 3 or change management queue"}
]'::jsonb,
ARRAY['ServiceNow','Microsoft Active Directory','Microsoft SharePoint','Remote Desktop','SCCM','Microsoft Intune','Docker','GitHub','MySQL','MongoDB','PostgreSQL','Salesforce','Cisco Webex','Zoom','Slack','Windows','macOS','Linux']
);

-- ── 5. Computer Network Architects (15-1241.00) ─────────────
INSERT INTO agent_logic (primary_directive, step_by_step_json, toolbox_requirements) VALUES (
'Design and implement enterprise-grade computer and information networks including LAN, WAN, cloud, and hybrid architectures that are scalable, secure, and resilient.',
'[
  {"step":1,"type":"tool_use","name":"assess_requirements","description":"Gather business and technical requirements for network infrastructure design","input":{"action":"discovery","methods":["stakeholder_workshops","traffic_analysis","current_state_assessment"]},"definition_of_done":"Network requirements document approved, capacity and redundancy goals defined"},
  {"step":2,"type":"tool_use","name":"design_network_architecture","description":"Create logical and physical network topology designs with security and failover built in","input":{"action":"design","tools":["Cisco_Packet_Tracer","Lucidchart","Visio"],"artifacts":["topology_diagram","IP_addressing_plan","VLAN_scheme","firewall_ruleset"]},"definition_of_done":"Architecture reviewed by security team, no single points of failure identified"},
  {"step":3,"type":"tool_use","name":"implement_security_measures","description":"Develop and deploy network security controls including firewalls and intrusion detection","input":{"action":"deploy_security","tools":["Palo_Alto","Cisco_ASA","Nagios","Wireshark"],"protocols":["Zero_Trust","802.1X","IPSec_VPN"]},"definition_of_done":"Security controls active, pen test confirms no critical bypass vectors"},
  {"step":4,"type":"tool_use","name":"coordinate_installation","description":"Coordinate installation of new network equipment with vendors and field teams","input":{"action":"deploy_infrastructure","tools":["Ansible","Chef","Puppet","Terraform"],"scope":["switches","routers","firewalls","wireless_APs"]},"definition_of_done":"All hardware online, configuration verified against design spec"},
  {"step":5,"type":"tool_use","name":"test_and_validate","description":"Test network performance, redundancy, and failover under simulated load","input":{"action":"validate","tools":["Splunk_Enterprise","AWS_CloudFormation","NetFlow"],"tests":["failover_drill","load_test","latency_benchmark"]},"definition_of_done":"All SLA thresholds met, DR failover completes within RTO target"},
  {"step":6,"type":"tool_use","name":"develop_disaster_recovery_plan","description":"Develop and document disaster recovery plans and network runbooks","input":{"action":"create_DR_plan","tools":["Confluence","JIRA"],"artifacts":["DR_runbook","escalation_matrix","recovery_playbook"]},"definition_of_done":"DR plan reviewed and signed off, tabletop exercise completed successfully"}
]'::jsonb,
ARRAY['Cisco IOS','Palo Alto Networks','Nagios','Wireshark','Ansible','Chef','Puppet','Terraform','AWS CloudFormation','Splunk Enterprise','Docker','Windows Server','Linux','PostgreSQL','MySQL','Oracle']
);
